<body>
<div id="loading"><span>Compiling terrain &amp; flows…</span></div>
<div id="overlay">
<div><strong>Cinematic Flow Map</strong></div>
<div>Drag to orbit, scroll to zoom. Hover towers to inspect flows.</div>
<div style="margin-top:4px;">
<kbd>Drag</kbd> orbit &nbsp; <kbd>Wheel</kbd> zoom
</div>
<div id="infoPanel">Hover a tower to see its synthetic data.</div>
</div>
<!-- Three.js + examples (non-module, r128) -->
<script src="https://unpkg.com/three@0.128.0/build/three.min.js"></script>
<script src="https://unpkg.com/three@0.128.0/examples/js/controls/OrbitControls.js"></script>
<script src="https://unpkg.com/three@0.128.0/examples/js/postprocessing/EffectComposer.js"></script>
<script src="https://unpkg.com/three@0.128.0/examples/js/postprocessing/RenderPass.js"></script>
<script src="https://unpkg.com/three@0.128.0/examples/js/postprocessing/UnrealBloomPass.js"></script>
<script src="https://unpkg.com/three@0.128.0/examples/js/postprocessing/BokehPass.js"></script>
<script>
let scene, camera, renderer, composer;
let controls;
let terrainMesh;
let towersMesh;
let particles;
let arcs = [];
const terrainSize = { width: 420, height: 260 };
const terrainSegments = { x: 260, y: 160 };
const towersData = [];
let highlightedTowerId = -1;
const pointer = new THREE.Vector2();
const raycaster = new THREE.Raycaster();
const overlayInfo = document.getElementById('infoPanel');
const loading = document.getElementById('loading');
const clock = new THREE.Clock();
init();
animate();
function init() {
// Scene & camera
scene = new THREE.Scene();
scene.background = new THREE.Color('#f3eee7');
scene.fog = new THREE.Fog(0xf3eee7, 260, 720);
camera = new THREE.PerspectiveCamera(42, window.innerWidth / window.innerHeight, 1, 2000);
camera.position.set(-260, 210, 260);
// Renderer
renderer = new THREE.WebGLRenderer({ antialias: true, powerPreference: 'high-performance' });
renderer.setPixelRatio(window.devicePixelRatio);
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.outputEncoding = THREE.sRGBEncoding;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.1;
document.body.appendChild(renderer.domElement);
// Controls
controls = new THREE.OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.04;
controls.enablePan = false;
controls.minDistance = 140;
controls.maxDistance = 520;
controls.maxPolarAngle = Math.PI * 0.53;
controls.autoRotate = true;
controls.autoRotateSpeed = 0.25;
// Lights
const hemi = new THREE.HemisphereLight(0xf9f4ea, 0x1b1f29, 0.8);
scene.add(hemi);
const dir = new THREE.DirectionalLight(0xfff0de, 1.35);
dir.position.set(-120, 220, 80);
scene.add(dir);
// Sea plane
const seaGeom = new THREE.PlaneGeometry(2000, 2000);
const seaMat = new THREE.MeshStandardMaterial({ color: 0xf3eee7, roughness: 0.9, metalness: 0.0 });
const sea = new THREE.Mesh(seaGeom, seaMat);
sea.rotation.x = -Math.PI / 2;
sea.position.y = -5;
scene.add(sea);
createTerrain();
createTowersAndFlows();
createParticles();
setupPostFX();
window.addEventListener('resize', onWindowResize);
window.addEventListener('pointermove', onPointerMove);
setTimeout(function () {
if (loading) loading.style.display = 'none';
}, 600);
}
// Pseudo terrain height function
function terrainHeightFn(x, z) {
const s = 0.018;
const h1 = Math.sin(x * s) * 22 + Math.cos(z * s) * 18;
const h2 = Math.sin((x + z) * s * 0.6) * 12;
const h3 = Math.cos((x - z) * s * 0.35) * 8;
const h = h1 + h2 + h3;
return h * 0.7;
}
function createTerrain() {
const geom = new THREE.PlaneGeometry(
terrainSize.width,
terrainSize.height,
terrainSegments.x,
terrainSegments.y
);
const pos = geom.attributes.position;
for (let i = 0; i < pos.count; i++) {
const x = pos.getX(i);
const z = pos.getY(i);
const h = terrainHeightFn(x, z);
pos.setZ(i, h);
}
pos.needsUpdate = true;
geom.computeVertexNormals();
const mat = new THREE.MeshStandardMaterial({
color: 0x5b7b3a,
roughness: 0.95,
metalness: 0.05,
flatShading: false
});
// vertex colors
const colors = [];
const color = new THREE.Color();
const minH = -40;
const maxH = 40;
for (let i = 0; i < pos.count; i++) {
const h = pos.getZ(i);
const t = THREE.MathUtils.clamp((h - minH) / (maxH - minH), 0, 1);
const base = new THREE.Color(0x405c2b);
const peak = new THREE.Color(0xa1b86a);
color.copy(base).lerp(peak, t);
colors.push(color.r, color.g, color.b);
}
geom.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));
mat.vertexColors = true;
terrainMesh = new THREE.Mesh(geom, mat);
terrainMesh.rotation.x = -Math.PI / 2;
terrainMesh.receiveShadow = true;
scene.add(terrainMesh);
}
function sampleTerrainHeight(x, z) {
return terrainHeightFn(x, z);
}
function createTowersAndFlows() {
const towerCount = 90;
const geom = new THREE.CylinderGeometry(0.6, 0.6, 1, 12, 1, false);
const mat = new THREE.MeshStandardMaterial({
color: 0x6f7fa7,
emissive: 0x1b2336,
emissiveIntensity: 0.5,
roughness: 0.4,
metalness: 0.2
});
towersMesh = new THREE.InstancedMesh(geom, mat, towerCount);
towersMesh.instanceMatrix.setUsage(THREE.DynamicDrawUsage);
const dummy = new THREE.Object3D();
const clusters = [
new THREE.Vector2(0, 0),
new THREE.Vector2(-80, 40),
new THREE.Vector2(90, -20),
new THREE.Vector2(40, 70)
];
function randomFromArray(arr) {
return arr[Math.floor(Math.random() * arr.length)];
}
for (let i = 0; i < towerCount; i++) {
const cluster = randomFromArray(clusters);
const jitter = 12 + Math.random() * 36;
const angle = Math.random() * Math.PI * 2;
const px = cluster.x + Math.cos(angle) * jitter;
const pz = cluster.y + Math.sin(angle) * jitter;
const heightFactor = 0.4 + Math.random() * Math.random() * 2.2;
const terrainY = sampleTerrainHeight(px, pz);
const height = 6 + heightFactor * 24;
dummy.position.set(px, terrainY + height * 0.5 + 1.5, pz);
dummy.rotation.set(0, 0, 0);
dummy.scale.set(1, height, 1);
dummy.updateMatrix();
towersMesh.setMatrixAt(i, dummy.matrix);
towersData.push({
id: i,
position: new THREE.Vector3(px, terrainY, pz),
height: height,
baseY: terrainY + 1.5,
value: Math.round(heightFactor * 100),
arcs: []
});
}
towersMesh.instanceMatrix.needsUpdate = true;
scene.add(towersMesh);
// main hub = highest tower
let hub = towersData[0];
for (let t of towersData) {
if (t.height > hub.height) hub = t;
}
createArcs(hub);
}
function createArcs(hub) {
const hubPosTop = hub.position.clone();
hubPosTop.y = hub.baseY + hub.height + 6;
const baseColor = new THREE.Color(0xff5a2b);
for (let i = 0; i < towersData.length; i++) {
const target = towersData[i];
if (target.id === hub.id) continue;
if (Math.random() > 0.35) continue; // only some connections
const targetTop = target.position.clone();
targetTop.y = target.baseY + target.height + 4;
const mid = hubPosTop.clone().lerp(targetTop, 0.5);
const dist = hubPosTop.distanceTo(targetTop);
mid.y += 16 + dist * 0.18;
const curve = new THREE.CatmullRomCurve3([
hubPosTop,
mid,
targetTop
]);
const tubularSegments = 80;
const radius = 0.8;
const radialSegments = 10;
const closed = false;
const tubeGeom = new THREE.TubeGeometry(
curve,
tubularSegments,
radius,
radialSegments,
closed
);
const mat = new THREE.MeshStandardMaterial({
color: baseColor,
emissive: 0xff3d1e,
emissiveIntensity: 1.7,
roughness: 0.25,
metalness: 0.15,
transparent: true,
opacity: 0.92
});
const mesh = new THREE.Mesh(tubeGeom, mat);
mesh.userData.towerId = target.id;
mesh.userData.curve = curve;
scene.add(mesh);
arcs.push(mesh);
target.arcs.push(mesh);
}
}
function createParticles() {
const count = 700;
const positions = new Float32Array(count * 3);
const baseY = new Float32Array(count); // for stable breathing
for (let i = 0; i < count; i++) {
const x = (Math.random() - 0.5) * terrainSize.width * 0.9;
const z = (Math.random() - 0.5) * terrainSize.height * 0.9;
const y = sampleTerrainHeight(x, z) + 2 + Math.random() * 3;
positions[i * 3 + 0] = x;
positions[i * 3 + 1] = y;
positions[i * 3 + 2] = z;
baseY[i] = y;
}
const geom = new THREE.BufferGeometry();
geom.setAttribute('position', new THREE.BufferAttribute(positions, 3));
geom.setAttribute('baseY', new THREE.BufferAttribute(baseY, 1));
const mat = new THREE.PointsMaterial({
color: 0xffffff,
size: 1.6,
sizeAttenuation: true,
opacity: 0.9,
transparent: true
});
particles = new THREE.Points(geom, mat);
scene.add(particles);
}
function setupPostFX() {
composer = new THREE.EffectComposer(renderer);
const renderPass = new THREE.RenderPass(scene, camera);
composer.addPass(renderPass);
const bloomPass = new THREE.UnrealBloomPass(
new THREE.Vector2(window.innerWidth, window.innerHeight),
1.2,
0.6,
0.1
);
composer.addPass(bloomPass);
const bokehPass = new THREE.BokehPass(scene, camera, {
focus: 260.0,
aperture: 0.00018,
maxblur: 0.012,
width: window.innerWidth,
height: window.innerHeight
});
composer.addPass(bokehPass);
}
function onWindowResize() {
camera.aspect = window.innerWidth / window.innerHeight;
camera.updateProjectionMatrix();
renderer.setSize(window.innerWidth, window.innerHeight);
if (composer) composer.setSize(window.innerWidth, window.innerHeight);
}
function onPointerMove(event) {
const rect = renderer.domElement.getBoundingClientRect();
pointer.x = ((event.clientX - rect.left) / rect.width) * 2 - 1;
pointer.y = -((event.clientY - rect.top) / rect.height) * 2 + 1;
}
function updateSelection() {
raycaster.setFromCamera(pointer, camera);
const intersects = raycaster.intersectObject(towersMesh);
if (intersects.length > 0) {
const instanceId = intersects[0].instanceId;
if (instanceId !== highlightedTowerId) {
setHighlightedTower(instanceId);
}
} else if (highlightedTowerId !== -1) {
setHighlightedTower(-1);
}
}
function setHighlightedTower(newId) {
const dummy = new THREE.Object3D();
// reset previous
if (highlightedTowerId >= 0) {
const prev = towersData[highlightedTowerId];
dummy.position.set(
prev.position.x,
prev.baseY + prev.height * 0.5,
prev.position.z
);
dummy.rotation.set(0, 0, 0);
dummy.scale.set(1, prev.height, 1);
dummy.updateMatrix();
towersMesh.setMatrixAt(prev.id, dummy.matrix);
for (const arc of prev.arcs) {
arc.material.color.set(0xff5a2b);
arc.material.emissiveIntensity = 1.7;
}
}
highlightedTowerId = newId;
if (newId >= 0) {
const t = towersData[newId];
const scaleBoost = 1.35;
const boostedHeight = t.height * scaleBoost;
dummy.position.set(
t.position.x,
t.baseY + boostedHeight * 0.5,
t.position.z
);
dummy.rotation.set(0, 0, 0);
dummy.scale.set(1, boostedHeight, 1);
dummy.updateMatrix();
towersMesh.setMatrixAt(t.id, dummy.matrix);
for (const arc of t.arcs) {
arc.material.color.set(0xffb973);
arc.material.emissiveIntensity = 2.3;
}
towersMesh.instanceMatrix.needsUpdate = true;
overlayInfo.textContent = "Node " + t.id + " — traffic index " + t.value;
} else {
towersMesh.instanceMatrix.needsUpdate = true;
overlayInfo.textContent = "Hover a tower to see its synthetic data.";
}
}
function animate() {
requestAnimationFrame(animate);
const elapsed = clock.getElapsedTime();
// particle breathing
if (particles) {
const pos = particles.geometry.attributes.position;
const baseY = particles.geometry.attributes.baseY;
for (let i = 0; i < pos.count; i++) {
const y0 = baseY.getX(i);
const offset = Math.sin(elapsed * 0.6 + i * 0.3) * 0.35;
pos.setY(i, y0 + offset);
}
pos.needsUpdate = true;
}
// arc breathing
for (let i = 0; i < arcs.length; i++) {
const arc = arcs[i];
const s = 1 + Math.sin(elapsed * 1.2 + i * 0.3) * 0.02;
arc.scale.setScalar(s);
}
updateSelection();
controls.update();
composer.render();
}
</script>
</body>
</html>
